// Parent — sealed with an explicit permits list
sealed interface Shape permits Circle, Square, Group {}

// Variant 1: final — leaf, cannot be extended further
final class Circle implements Shape {
  private final double r;
  Circle(double r) { this.r = r; }
}

// Variant 2: sealed — this subtype ALSO closes its own hierarchy
sealed class Square implements Shape permits UnitSquare {}
final class UnitSquare extends Square { }

// Variant 3: non-sealed — opts BACK OUT of sealing
//            (this subtype can be extended freely by anyone)
non-sealed class Group implements Shape { }
class CustomGroup extends Group { }   // OK, Group opened itself up

// File: SealedDemo.java (requires Java 17+, --enable-preview on 17-20 for record patterns)
// Run: javac SealedDemo.java && java SealedDemo

public class SealedDemo {

  // Closed hierarchy — Shape has EXACTLY three implementations
  sealed interface Shape permits Circle, Square, Triangle {}

  record Circle(double r) implements Shape {}
  record Square(double side) implements Shape {}
  record Triangle(double base, double height) implements Shape {}

  // Exhaustive switch — compiler proves every case is handled
  // NO default needed. If we add a new Shape subtype tomorrow,
  // this stops compiling until we handle it.
  static double area(Shape s) {
    return switch (s) {
      case Circle c   -> Math.PI * c.r() * c.r();
      case Square sq  -> sq.side() * sq.side();
      case Triangle t -> 0.5 * t.base() * t.height();
    };
  }

  // Same, but using record deconstruction (Java 21+)
  static String describe(Shape s) {
    return switch (s) {
      case Circle(double r)             -> "circle r=" + r;
      case Square(double side)          -> "square " + side;
      case Triangle(double b, double h) -> "triangle " + b + "x" + h;
    };
  }

  public static void main(String[] args) {
    Shape[] shapes = {
      new Circle(2),
      new Square(3),
      new Triangle(4, 5),
    };

    for (Shape sh : shapes) {
      System.out.printf("%-30s area=%.2f%n", describe(sh), area(sh));
    }
  }
}

// Output:
//   circle r=2.0                   area=12.57
//   square 3.0                     area=9.00
//   triangle 4.0x5.0               area=10.00
//
// NOW imagine we add `record Pentagon(...) implements Shape {}`.
// The `sealed interface Shape` will FAIL TO COMPILE until we add Pentagon
// to the permits list, and both `area()` and `describe()` will fail to compile
// until we handle Pentagon. That's the safety net sealed types give you.

